{"cmd":"$repos = @('popdam3','popcrm-web','poppim-web','directus')
foreach ($repo in $repos) {
  $existing = gh api "repos/u2giants/$repo/rulesets" --jq '.[] | select(.name=="Block app-owned shared DB migrations") | .id'
  if ($existing) {
    Write-Output "$repo already has ruleset $existing"
    continue
  }
  $payload = @{
    name = 'Block app-owned shared DB migrations'
    target = 'push'
    enforcement = 'active'
    rules = @(
      @{
        type = 'file_path_restriction'
        parameters = @{
          restricted_file_paths = @('supabase/migrations/**/*')
        }
      }
    )
  } | ConvertTo-Json -Depth 10
  $tmp = New-TemporaryFile
  Set-Content -LiteralPath $tmp -Value $payload -NoNewline
  gh api --method POST "repos/u2giants/$repo/rulesets" --input $tmp --jq '{id,name,target,enforcement,rules}'
  Remove-Item -LiteralPath $tmp
}","workdir":"D:\repos","shell":"powershell","yield_time_ms":30000,"max_output_tokens":20000}

